func registerDefaultErrorHandler() error {
	m := map[string]func(http.ResponseWriter, *http.Request){
		"401":	unauthorized,
		"402":	paymentRequired,
		"403":	forbidden,
		"404":	notFound,
		"405":	methodNotAllowed,
		"500":	internalServerError,
		"501":	notImplemented,
		"502":	badGateway,
		"503":	serviceUnavailable,
		"504":	gatewayTimeout,
		"417":	invalidxsrf,
		"422":	missingxsrf,
		"413":	payloadTooLarge,
	}
	for e, h := range m {
		if _, ok := ErrorMaps[e]; !ok {
			ErrorHandler(e, h)
		}
	}
	return nil
}
